var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"새로운 계약이요?","JPN":"新しい契約ですか？","ENG":"A new contract?","TWN":"新的契約嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"계약에 변경 사항이 있다면 발렌티누스 수도원에…….","JPN":"契約更新なら、バレンチヌス修道院に……","ENG":"If there are any changes to the contract, please contact the Valentinus Monastery...","TWN":"契約內容有變動的話，要去跟修道院說……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"제 저주를 풀 방법을 같이 찾고 싶다고요?","JPN":"私の呪いを解く方法を一緒に探したい？","ENG":"You want to help me find a way to break my curse together?","TWN":"你說你想跟我一起找出解除詛咒的方法嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"매일 무제한 포도 주스 제공에 의뢰인님의 곁을 허가…….","JPN":"毎日ブドウジュース飲み放題で、依頼人さんのそばにいてもいい……？","ENG":"Unlimited daily grape juice in exchange for permission to stay by your side...","TWN":"每天提供無限量的葡萄汁，還可以待在委託人的身邊……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"흠흠!","JPN":"おっほん！","ENG":"Ahem!","TWN":"咳，咳！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"저는 불량식품처럼 이득을 좇는 속물이 아니에요.","JPN":"私はお菓子さんみたいに、利益を求める俗物ではありません。","ENG":"I'm not some greedy opportunist like Junk food, who only cares about profit.","TWN":"我可不是那種像垃圾食物那種追求利益的俗人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"아무리 달콤한 조건으로 유혹한들, 제가 꼬임에 넘어가는 일은 없을 거라고요.","JPN":"いくら甘い条件で誘惑したって、私がそれに乗ることはないんですよ。","ENG":"No matter how sweet the offer, I won't fall for such temptations.","TWN":"就算你想用這些很棒的條件來誘惑我，我也不會輕易上當的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"……침이나 닦으라고요?","JPN":"……涎を拭けって？","ENG":"...I should first wipe off my drool?","TWN":"……我流口水啦？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"이, 이건 어쩔 수 없는 본능이에요.","JPN":"こ、これは本能だから仕方ないです。","ENG":"Th-this is just an uncontrollable instinct.","TWN":"這，這是我的本能反應，能怎麼辦！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"의뢰인님이 그렇게 맛있는 냄새를 풍기는데, 가만히 있는 것도 고역이란 말이에요.","JPN":"依頼人さんからこんなにも美味しそうな匂いがするのに、じっとしてるのも大変なんですよ。","ENG":"How am I supposed to just sit here when you smell so delicious?","TWN":"誰叫你身上的味道那麼美味，我忍得很痛苦欸。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"이런 저에게 곁을 내주려 하다니…… 겁이 없는 건지, 믿는 구석이 있는 건지…….","JPN":"こんな私をそばに置こうだなんて……大胆なのか、自信があるのか……","ENG":"You're actually letting me stay near you... I can't tell if you're fearless or just have something up your sleeve...","TWN":"這樣你竟然還敢把我留在身邊…你是膽子太大，還是太有自信……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"구하라. 그러면 받을 것이다. 찾아라. 그러면 찾을 것이다. 문을 두드려라. 그러면 열릴 것이다.","JPN":"求めよ、そうすれば、与えられるであろう。捜せ、そうすれば、見いだすであろう。門をたたけ、そうすれば、開くであろう。","ENG":"Ask, and you shall receive. Seek, and you shall find. Knock, and the door will be opened to you.","TWN":"求，便會得。找，便會到。敲門，便會開。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L27_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"결국, 저주를 풀 방법은 제가 찾아야 한다는 소리예요.","JPN":"結局、呪いを解く方法は自分で探さないといけないという意味です。","ENG":"So in the end, it means I have to find a way to break the curse myself.","TWN":"結果，解除詛咒的方法還是得我自己找的意思嘛。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"회사에서 어쩌다 들었는데, 의뢰인님, 사실 대단한 사람이라면서요?","JPN":"会社で聞いたんですけど、依頼人さん、本当はすごい人なんですって？","ENG":"I happened to hear something at the company. It turns out you're quite the big deal, aren't you?","TWN":"這是我在公司湊巧聽到的，聽說你其實很厲害喔？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"그렇다면 정말로 제 저주를 풀 방법을 찾아낼지도 모르겠네요.","JPN":"それなら、本当に私の呪いを解く方法を見つけられるかもしれませんね。","ENG":"In that case, maybe you really will find a way to break my curse.","TWN":"那說不定，你真的能找到解除詛咒的方法。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"믿어볼게요. 신뢰란 건 앞으로도 계속 쌓아나가면 되니까.","JPN":"信じてみます。信頼というものは、これから積んでいけばいいですから。","ENG":"I'll trust you. After all, trust is something we can keep building over time.","TWN":"我就相信你吧。反正信任這種事都是慢慢累積的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"혹시…… 신뢰의 증표로 의뢰인님의 목에 이빨 자국을 내도 될까요?","JPN":"あの……信頼の証に依頼人の首筋を噛んでみてもいいでしょうか？","ENG":"As a token of trust... would it be okay if I left a bite mark on your neck?","TWN":"那個……我可以在你脖子上留下齒印當作信物嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"빈혈은 안 나게 해드릴게요.","JPN":"貧血にはしませんよ。","ENG":"I'll make sure you don't get lightheaded from blood loss.","TWN":"我會小心不讓你失血過多的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"일단 도장부터 찍으라고요? 아, 알겠어요…….","JPN":"まずはハンコから押せって？　わ、わかりました……","ENG":"Sign it first, you say? Ugh, all right...","TWN":"要先蓋章喔？喔，好啦……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"찍으면 깨물어도 되는 거죠?","JPN":"ハンコ押したら噛んでもいいですよね？","ENG":"Once I sign, I'm allowed to take a bite, right?","TWN":"蓋下去之後就可以咬一口對吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"}]`);export{e as default};